const aiResp = $('Call Kimi K2.5').item.json;
const rows = $('Load Tenant Context').all().map(i => i.json);
const cfg = rows[0] || {};
const phone = $('Webhook').item.json.body.message.phone;
const content = aiResp?.choices?.[0]?.message?.content?.trim()
  || cfg.fallback_msg
  || 'Lo siento, no entendí bien. ¿Puedes repetirlo?';
return [{ json: { phone, content } }];
